import React, { useState } from 'react';
import axios from 'axios';
import { ClipboardPaste, Loader2, CheckCircle, AlertCircle, Info } from 'lucide-react';
import { generarNombreImagen } from '../utils/helpers';

const GestionInventario = ({ localId, onComplete }) => {
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);

  const procesarYEnviar = async (e) => {
    const pasteData = e.clipboardData.getData('Text');
    if (!pasteData || !localId) return;

    setLoading(true);
    setStatus(null);

    try {
      // 1. Convertir el pegado (TSV) en filas
      const rows = pasteData.split('\n').filter(row => row.trim() !== "");
      
      // Detectar cabeceras y limpiar datos
      const headers = rows[0].toLowerCase().split('\t').map(h => h.trim());
      
      const productosProcesados = rows.slice(1).map(row => {
        const values = row.split('\t');
        const prod = {};
        headers.forEach((header, i) => {
          prod[header] = values[i] ? values[i].trim() : "";
        });

        // Aplicamos la lógica para la nube y Cloudinary
        return {
          producto: `${prod.tipo || ''} ${prod.marca || ''} ${prod.contenido || ''}`.trim(),
          categoria: prod.categoria || 'Almacén',
          precioNuevo: Number(prod.precioNuevo) || 0,
          precioViejo: Number(prod.precioViejo) || 0,
          stock: Number(prod.stock) || 0,
          peso: Number(prod.peso) || 0,
          // Sincronización con el helper de imágenes
          publicId: generarNombreImagen(prod.tipo || '', prod.marca || '', prod.contenido || ''),
          local: localId
        };
      });

      // 2. Envío al Backend (Usando el puerto con menos conflictos)
      const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
      
      const response = await axios.post(`${API_URL}/api/ofertas/bulk`, {
        productos: productosProcesados,
        localId: localId
      });

      setStatus({ 
        type: 'success', 
        msg: `✅ ${productosProcesados.length} productos sincronizados con éxito.` 
      });
      
      if (onComplete) onComplete(); // Recarga la lista de abajo
    } catch (error) {
      console.error("Error en carga:", error);
      const msgError = !error.response 
        ? "Servidor desconectado. Revisa si el backend está corriendo." 
        : "Error en el formato de los datos pegados.";
      setStatus({ type: 'error', msg: msgError });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={containerStyle}>
      <div style={headerStyle}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <ClipboardPaste size={24} color="#0284c7" />
          <h3 style={{ margin: 0, color: '#0c4a6e' }}>Carga Rápida desde Excel</h3>
        </div>
        <div style={badgeInstrucciones}>
          <Info size={14} />
          <span>Copia las celdas en Excel y pégalas aquí</span>
        </div>
      </div>

      <div style={{ position: 'relative' }}>
        <textarea
          onPaste={procesarYEnviar}
          placeholder="Haz clic aquí y presiona Ctrl + V para cargar tus productos..."
          style={inputPegadoStyle}
          disabled={loading}
        />
        
        {loading && (
          <div style={loaderOverlay}>
            <Loader2 className="animate-spin" size={32} color="#0284c7" />
            <p style={{ fontWeight: '600', color: '#0284c7' }}>Sincronizando con Atlas...</p>
          </div>
        )}
      </div>

      {status && (
        <div style={status.type === 'success' ? successMsg : errorMsg}>
          {status.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
          {status.msg}
        </div>
      )}

      <p style={tipStyle}>
        * Asegúrate de incluir la fila de títulos en tu selección de Excel: 
        <strong> tipo, marca, contenido, categoria, precioNuevo, precioViejo, stock</strong>
      </p>
    </div>
  );
};

// --- ESTILOS MODERNOS ---
const containerStyle = { background: '#ffffff', padding: '25px', borderRadius: '24px', boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)', border: '1px solid #e2e8f0', marginBottom: '30px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const badgeInstrucciones = { display: 'flex', alignItems: 'center', gap: '6px', background: '#f0f9ff', color: '#0369a1', padding: '6px 12px', borderRadius: '12px', fontSize: '0.8rem', fontWeight: '600' };
const inputPegadoStyle = { width: '100%', height: '120px', padding: '20px', borderRadius: '16px', border: '2px dashed #cbd5e1', background: '#f8fafc', fontSize: '1rem', color: '#475569', outline: 'none', transition: 'all 0.2s ease', resize: 'none' };
const loaderOverlay = { position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(255,255,255,0.9)', borderRadius: '16px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '10px' };
const successMsg = { marginTop: '15px', display: 'flex', alignItems: 'center', gap: '10px', background: '#f0fdf4', color: '#166534', padding: '12px 20px', borderRadius: '12px', fontWeight: '600' };
const errorMsg = { marginTop: '15px', display: 'flex', alignItems: 'center', gap: '10px', background: '#fef2f2', color: '#991b1b', padding: '12px 20px', borderRadius: '12px', fontWeight: '600' };
const tipStyle = { marginTop: '15px', fontSize: '0.75rem', color: '#94a3b8', textAlign: 'center' };

export default GestionInventario;
